export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:45。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "監控切線開始。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是前幾輪顧言已經驗證過的規律——校慶閉幕前，舊監控系統需要切換到閉幕備援線路。整個過程大約十七分鐘。在這十七分鐘裡，後台走廊、裝卸區、鐘樓外圍的攝像頭會逐一離線，再逐一恢復。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是被駭入。不是被人為關閉。是老舊系統的正常切換流程。技術志工在監控室裡操作。每一輪都一樣。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十七分鐘。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在後台走廊的轉角。他看著走廊盡頭的攝像頭——紅色指示燈滅了。一個。兩個。三個。像一排眼睛依次閉上。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）開始了。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）十七分鐘。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三件事。同時做。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿出手機。最後看了一眼時間。21:45。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他把手機關了螢幕。放進口袋。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越。第一件事。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一頭，韓越推著一輛輪式推車往鐘樓方向走。推車上蓋著帆布。帆布下面是假死道具——黑雨衣、舞台假人、裝沙器材袋、舊制服外套。顧言的背包已經綁在假人上了。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的通行證掛在脖子上。藍底白字。舞台組。這條動線是舞台組搬器材的合理路線——從倉庫到鐘樓背面的戶外器材服務走廊，途中會經過兩個監控死角。在監控切線的十七分鐘裡，這段路完全沒有記錄。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "推車的輪子在地上碾過。聲音很穩。韓越走路的方式像在搬器材——不快不慢，不回頭，不東張西望。像一個做了十幾次同樣工作的志工。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他要把道具送到鐘樓背面。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）維修庭院。低層平台。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:22 之前。放到定位。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的背影消失在走廊轉角。帆布在推車上輕輕晃動。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二件事。我。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從轉角走出來。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有往鐘樓走。也沒有往後台走。他往禮堂側區方向走——那裡是閉幕活動的公共區域，家長和學生正在入座。他走進人群。在幾百個人之間，他只是一個穿校服的學生。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他從側區的洗手間通道拐進了一條過渡走廊——連接禮堂側區和後台準備區的通道。這裡沒有攝像頭。監控切線之前就沒有。不是死角。是公共區域和後台之間的灰色地帶。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在這裡停下來。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不能進真正死角。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）死角會讓邵叔警覺。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我要從公開視線裡消失——但不是消失到看不見的地方。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是消失到「一個學生去洗手間」的程度。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）等監控恢復之後，我再出現。往鐘樓方向走。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那時候邵叔會看見我。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）看見我帶著假相機包。往鐘樓走。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在走廊的牆上。牆面是冷的。瓷磚。和醫務室的牆一樣冷。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第三件事。星棠。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠在後台準備區。她背著器材箱，相機掛在脖子上，藍色工作證別在胸口。她的動線是從後台準備區往直播備份線附近移動——那裡有一個安全暫存點，是紀錄組存放閉幕素材的臨時區域。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不是在跑。不是在偷偷摸摸。她在走。像一個紀錄組成員在確認閉幕素材流程。因為她就是。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她要把證據包送到直播備份線附近。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是接入。是放到附近。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）23:00 之前她親手接入。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）現在——先到定位。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他閉上眼睛。聽著走廊外面的聲音——雨聲、遠處禮堂的音樂聲、腳步聲、廣播聲。所有聲音疊在一起，像一鍋正在煮的東西，什麼都分不清。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔現在在看什麼。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不是在猜。他是在算。前七輪的經驗，讓他比任何人都清楚邵叔在閉幕前會看什麼、怎麼看、透過誰看。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不在監控室。他在指揮區。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他透過林主任和指揮室的警員看。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他看到的是——", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言在腦中展開邵叔的視野。不是透視。是推演。是七條命換來的情報地圖。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一。我今天查過鐘樓天線屋的資料。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）上午。我在圖書館終端查了「鐘樓天線屋」「舊廣播線」「校慶直播備援」。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這些查詢紀錄在校內系統裡。林主任能看到。林主任會回報邵叔。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔看到的是——顧言在查鐘樓的傳輸線路。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）符合他預期。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二。我在林主任能聽見的地方說過半句話。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「如果直播線被切，只剩鐘樓那條舊線。」", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任聽到了。林主任回報了。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔看到的是——顧言在考慮用鐘樓備用傳輸線送東西出去。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）符合他預期。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第三。許星棠仍在後台附近活動。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她的位置在直播備份線附近。紀錄組成員。合理。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔看到的是——許星棠在後台。沒有離開。沒有往校外走。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）符合他預期。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第四。韓越的通行卡。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越的舞台組通行證仍然是有效變數。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔知道韓越有通行卡。他知道韓越和許星棠走得近。他隨時可以切斷那張卡。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但他還沒有切。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）因為現在還不需要。因為一切看起來都在他的控制範圍裡。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）符合他預期。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言睜開眼睛。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）全部符合。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他看到的一切——都在他預期之內。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）顧言查過鐘樓。顧言接近鐘樓動線。許星棠在後台。韓越的卡可以隨時切。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）沒有一樣東西會讓他覺得不對。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）沒有一樣東西會讓他提前動手。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這就是我要的。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）讓他覺得一切都在控制裡。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）讓他覺得——他只需要等 22:22。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊外面的廣播切了一段閉幕提醒。播音員的聲音穿過牆壁，變成含糊的嗡嗡聲。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:52。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "監控還沒恢復。還有十分鐘。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從牆邊站直。整理了一下校服。把假相機包的背帶調到最順的位置。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）再等十分鐘。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）監控恢復之後——", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我走出去。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）往鐘樓方向。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）帶著假包。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）讓他看見。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸了一口氣。走廊裡的空氣潮濕、沉悶。遠處傳來禮堂裡的掌聲——閉幕節目還在進行。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:02。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊盡頭的攝像頭紅色指示燈亮了。一個。兩個。三個。像一排眼睛依次睜開。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "監控恢復了。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）十七分鐘。過了。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越應該到了。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）星棠應該在定位了。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）現在——", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）輪到我了。", background: Background.Chapter_8_Ch8_Act11_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從過渡走廊走出來。回到禮堂側區的公共通道。人群在身邊流動。家長、學生、老師。沒有人注意他。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他調整了一下假相機包的位置。讓它更顯眼一點。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他開始走。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "往鐘樓方向。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:05。", background: Background.Chapter_8_Ch8_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在下。", background: Background.Chapter_8_Ch8_Act11_S0 },
];
